function solve(n: number, edges: number[][]): number {
    // Build the graph
    const graph: number[][] = new Array(n).fill(0).map(() => new Array<number>());
    for (const [u, v, w] of edges) {
        graph[u].push([v, w]);
    }

    // Dijkstra's algorithm with state tracking
    // Each state is (node, hasSwitchUsed)
    // hasSwitchUsed is a boolean indicating whether the switch at this node has been used
    // We use a priority queue to track the minimum cost to reach each state
    const pq: [number, number, number][] = [];
    pq.push([0, 0, 0]); // (cost, node, hasSwitchUsed)
    const dist: Map<string, number> = new Map();
    dist.set("0_0", 0);

    while (pq.length > 0) {
        // Sort the priority queue by cost
        pq.sort((a, b) => a[0] - b[0]);
        const [cost, node, hasSwitchUsed] = pq.shift() as [number, number, number];

        // If we've already found a better path to this state, skip
        const key = `${node}_${hasSwitchUsed}`;
        if (dist.has(key) && dist.get(key) < cost) {
            continue;
        }

        // If we've reached the destination
        if (node === n - 1) {
            return cost;
        }

        // Explore neighbors
        for (const [v, w] of graph[node]) {
            // Regular edge
            const newCost = cost + w;
            const newKey = `${v}_0`;
            if (!dist.has(newKey) || dist.get(newKey) > newCost) {
                dist.set(newKey, newCost);
                pq.push([newCost, v, 0]);
            }

            // Reverse edge (if switch hasn't been used)
            if (!hasSwitchUsed) {
                const reverseCost = cost + 2 * w;
                const reverseKey = `${v}_1`;
                if (!dist.has(reverseKey) || dist.get(reverseKey) > reverseCost) {
                    dist.set(reverseKey, reverseCost);
                    pq.push([reverseCost, v, 1]);
                }
            }
        }
    }

    // If we can't reach the destination
    return -1;
}

